import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract CreatureToken is ERC721, Ownable, ReentrancyGuard {
    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public totalSupply;
    bool public mintingAvailable = true;
    address public proxyRegistryAddress;
    string public baseURI;

    struct PackSizes {
        uint256 single;
        uint256 nickelPack; // 5 creatures
        uint256 dimePack;   // 10 creatures
        uint256 dubPack;    // 20 creatures
    }

    PackSizes public packSizes = PackSizes({
        single: 1,
        nickelPack: 5,
        dimePack: 10,
        dubPack: 20
    });

    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);

    constructor(string memory name, string memory symbol, string memory _baseURI) ERC721(name, symbol) {
        baseURI = _baseURI;
    }

    modifier whenMintingIsAvailable() {
        require(mintingAvailable, "Minting is not available");
        _;
    }

    function setProxyRegistryAddress(address _proxyRegistryAddress) external onlyOwner {
        proxyRegistryAddress = _proxyRegistryAddress;
    }

    function toggleMintingAvailability() external onlyOwner {
        mintingAvailable = !mintingAvailable;
    }

    function mint(uint256 _quantity, uint256 _type) external payable whenMintingIsAvailable nonReentrant {
        require(_quantity == packSizes.single || _quantity == packSizes.nickelPack || _quantity == packSizes.dimePack || _quantity == packSizes.dubPack, "Invalid pack size");
        require(totalSupply + _quantity <= MAX_SUPPLY, "Exceeds max supply");

        uint256 startSupply = totalSupply;
        uint256 endSupply = startSupply + _quantity;

        for (uint256 i = startSupply + 1; i <= endSupply; i++) {
            _safeMint(msg.sender, i);
        }

        totalSupply = endSupply;
    }

    function canMint(uint256 _quantity, uint256 _type) external view returns (bool) {
        return mintingAvailable && (_quantity == packSizes.single || _quantity == packSizes.nickelPack || _quantity == packSizes.dimePack || _quantity == packSizes.dubPack) && totalSupply + _quantity <= MAX_SUPPLY;
    }

    function transferOwnership(uint256 tokenId, address to) external nonReentrant {
        require(_isApprovedOrOwner(_msgSender(), tokenId), "Not owner nor approved");
        safeTransferFrom(_msgSender(), to, tokenId);
    }

    function _baseURI() internal view override returns (string memory) {
        return baseURI;
    }

    function _beforeTokenTransfer(address from, address to, uint256 tokenId)
        internal
        override(ERC721)
    {
        super._beforeTokenTransfer(from, to, tokenId);
        emit Transfer(from, to, tokenId);
    }
}
